  // inside here, TypeScript narrows user to User and address to { city: string; zip?: string }
  console.log(user.address.city);
}

interface Logger {
  log?(message: string): void;   // optional method
}

declare const logger: Logger | null;

// Call only if logger and logger.log both exist
