// instanceof guard with ?.
class ApiError extends Error {
  constructor(public status: number, message: string) { super(message); }
}

function handleError(err: unknown): string {
  // err?.message would be an error — err is unknown, not an object
  // use instanceof first
  if (err instanceof ApiError) {
    return `API ${err.status}: ${err.message}`;
  }
  if (err instanceof Error) {
    return err.message;
  }
  return 'Unknown error';
}

interface ApiResponse<T> {
  data?: T;
  error?: { code: number; message: string };
  meta?: { total: number; page: number };
}

@Injectable({ providedIn: 'root' })
class DataService {
  private readonly http = inject(HttpClient);

  getUsers(): Observable<User[]> {
    return this.http.get<ApiResponse<User[]>>('/api/users').pipe(
      map(res => res.data ?? []),
      catchError(err => {
        // Optional chaining on the Angular HTTP error response
        const message = err?.error?.message ?? 'Failed to load users';
        console.error(message);
        return of([]);
      })
    );
  }

  getPaginationInfo(res: ApiResponse<unknown>): string {
    const total = res.meta?.total ?? 0;
    const page  = res.meta?.page  ?? 1;
    return `Page ${page} of ${Math.ceil(total / 20)}`;
  }
}

@Component({ selector: 'app-detail', template: '' })
class DetailComponent implements OnInit {
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);

  ngOnInit(): void {
    // route.snapshot.params can have missing keys
    const id = this.route.snapshot.params['id']
      ?? this.route.snapshot.queryParams['id']
      ?? null;

    if (!id) {
      this.router.navigate(['/not-found']);
      return;
    }

    // Safe access to optional route data
    const title = this.route.snapshot.data?.['title'] ?? 'Detail';
    document.title = title;
  }
}

